    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        //     {
        //         "symbol": "BTC-USD-PERP",
        //         "oracle_price": "68465.17449906",
        //         "mark_price": "68465.17449906",
        //         "last_traded_price": "68495.1",
        //         "bid": "68477.6",
        //         "ask": "69578.2",
        //         "volume_24h": "5815541.397939004",
        //         "total_volume": "584031465.525259686",
        //         "created_at": 1718170156581,
        //         "underlying_price": "67367.37268422",
        //         "open_interest": "162.272",
        //         "funding_rate": "0.01629574927887",
        //         "price_change_rate_24h": "0.009032"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object percentage = this.safeString(ticker, "price_change_rate_24h");
        if (Helpers.isTrue(!Helpers.isEqual(percentage, null)))
        {
            percentage = Precise.stringMul(percentage, "100");
        }
        Object last = this.safeString(ticker, "last_traded_price");
        Object marketId = this.safeString(ticker, "symbol");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object timestamp = this.safeInteger(ticker, "created_at");
        final Object finalPercentage = percentage;
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", ParadexCore.this.iso8601(timestamp) );
            put( "high", null );
            put( "low", null );
            put( "bid", ParadexCore.this.safeString(ticker, "bid") );
            put( "bidVolume", null );
            put( "ask", ParadexCore.this.safeString(ticker, "ask") );
            put( "askVolume", null );
            put( "vwap", null );
            put( "open", null );
            put( "close", last );
            put( "last", last );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", finalPercentage );
            put( "average", null );
            put( "baseVolume", null );
            put( "quoteVolume", ParadexCore.this.safeString(ticker, "volume_24h") );
            put( "markPrice", ParadexCore.this.safeString(ticker, "mark_price") );
            put( "info", ticker );
        }}, market);
    }

    /**
     * @method
     * @name paradex#fetchOrderBook
     * @description fetches information on open orders with bid (buy) and ask (sell) prices, volumes and other data
     * @see https://docs.paradex.trade/api/prod/markets/get-orderbook
     * @param {string} symbol unified symbol of the market to fetch the order book for
     * @param {int} [limit] the maximum amount of order book entries to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} A dictionary of [order book structures]{@link https://docs.ccxt.com/?id=order-book-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOrderBook(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object limit = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "market", Helpers.GetValue(market, "id") );
            }};
            Object response = (this.publicGetOrderbookMarket(this.extend(request, parameters))).join();
            //
            //     {
            //         "market": "BTC-USD-PERP",
            //         "seq_no": 14115975,
            //         "last_updated_at": 1718172538340,
            //         "asks": [
            //             [
            //                 "69578.2",
            //                 "3.019"
            //             ]
            //         ],
            //         "bids": [
            //             [
            //                 "68477.6",
            //                 "0.1"
            //             ]
            //         ]
            //     }
            //
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "depth", limit);
            }
            Object timestamp = this.safeInteger(response, "last_updated_at");
            Object orderbook = this.parseOrderBook(response, Helpers.GetValue(market, "symbol"), timestamp);
            Helpers.addElementToObject(orderbook, "nonce", this.safeInteger(response, "seq_no"));
            return orderbook;
        });

    }

    /**
     * @method
     * @name paradex#fetchTrades
     * @description get the list of most recent trades for a particular symbol
     * @see https://docs.paradex.trade/api/prod/trades/trades
     * @param {string} symbol unified symbol of the market to fetch trades for
     * @param {int} [since] timestamp in ms of the earliest trade to fetch
     * @param {int} [limit] the maximum amount of trades to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] the latest time in ms to fetch trades for
     * @param {boolean} [params.paginate] default false, when true will automatically paginate by calling this endpoint multiple times
     * @returns {Trade[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=public-trades}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTrades(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object since = Helpers.getArg(optionalArgs, 0, null);
            Object limit = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object paginate = false;
            var paginateparametersVariable = this.handleOptionAndParams(parameters, "fetchTrades", "paginate");
            paginate = ((java.util.List<Object>) paginateparametersVariable).get(0);
            parameters = ((java.util.List<Object>) paginateparametersVariable).get(1);
            if (Helpers.isTrue(paginate))
            {
                return (this.fetchPaginatedCallCursor("fetchTrades", symbol, since, limit, parameters, "next", "cursor", null, 100)).join();
            }
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "market", Helpers.GetValue(market, "id") );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "page_size", Helpers.mathMin(limit, 1000));
            }
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "start_at", since);
            }
            var requestparametersVariable = this.handleUntilOption("end_at", request, parameters);
            request = ((java.util.List<Object>) requestparametersVariable).get(0);
            parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
            Object response = (this.publicGetTrades(this.extend(request, parameters))).join();
            //
            //     {
            //         "next": "...",
            //         "prev": "...",
            //         "results": [
            //             {
            //                 "id": "1718154353750201703989430001",
            //                 "market": "BTC-USD-PERP",
            //                 "side": "BUY",
            //                 "size": "0.026",
            //                 "price": "69578.2",
            //                 "created_at": 1718154353750,
            //                 "trade_type": "FILL"
            //             }
            //         ]
            //     }
            //
            Object trades = this.safeList(response, "results", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(trades)); i++)
            {
                Helpers.addElementToObject(Helpers.GetValue(trades, i), "next", this.safeString(response, "next"));
            }
            return this.parseTrades(trades, market, since, limit);
        });

    }

    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades (public)
        //
        //     {
        //         "id": "1718154353750201703989430001",
        //         "market": "BTC-USD-PERP",
        //         "side": "BUY",
        //         "size": "0.026",
        //         "price": "69578.2",
        //         "created_at": 1718154353750,
        //         "trade_type": "FILL"
        //     }
        //
        // fetchMyTrades (private)
        //
        //     {
        //         "id": "1718947571560201703986670001",
        //         "side": "BUY",
        //         "liquidity": "TAKER",
        //         "market": "BTC-USD-PERP",
        //         "order_id": "1718947571540201703992340000",
        //         "price": "64852.9",
        //         "size": "0.01",
        //         "fee": "0.1945587",
        //         "fee_currency": "USDC",
        //         "created_at": 1718947571569,
        //         "remaining_size": "0",
        //         "client_id": "",
        //         "fill_type": "FILL"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(trade, "market");
        market = this.safeMarket(marketId, market);
        Object id = this.safeString(trade, "id");
        Object timestamp = this.safeInteger(trade, "created_at");
        Object priceString = this.safeString(trade, "price");
        Object amountString = this.safeString(trade, "size");
        Object side = this.safeStringLower(trade, "side");
        Object liability = this.safeStringLower(trade, "liquidity", "taker");
        Object isTaker = Helpers.isEqual(liability, "taker");
        Object takerOrMaker = ((Helpers.isTrue((isTaker)))) ? "taker" : "maker";
        Object currencyId = this.safeString(trade, "fee_currency");
        Object code = this.safeCurrencyCode(currencyId);
        final Object finalMarket = market;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", id );
            put( "order", ParadexCore.this.safeString(trade, "order_id") );
            put( "timestamp", timestamp );
            put( "datetime", ParadexCore.this.iso8601(timestamp) );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "type", null );
            put( "takerOrMaker", takerOrMaker );
            put( "side", side );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", null );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "cost", ParadexCore.this.safeString(trade, "fee") );
                put( "currency", code );
                put( "rate", null );
            }} );
        }}, market);
    }

