    public java.util.concurrent.CompletableFuture<Object> prepareParadexDomain(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object l1 = Helpers.getArg(optionalArgs, 0, false);
            Object systemConfig = (this.getSystemConfig()).join();
            if (Helpers.isTrue(Helpers.isEqual(l1, true)))
            {
                Object l1D = new java.util.HashMap<String, Object>() {{
                    put( "name", "Paradex" );
                    put( "chainId", Helpers.GetValue(systemConfig, "l1_chain_id") );
                    put( "version", "1" );
                }};
                return l1D;
            }
            Object domain = new java.util.HashMap<String, Object>() {{
                put( "name", "Paradex" );
                put( "chainId", Helpers.GetValue(systemConfig, "starknet_chain_id") );
                put( "version", 1 );
            }};
            return domain;
        });

    }

    public java.util.concurrent.CompletableFuture<Object> retrieveAccount()
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object cachedAccount = this.safeDict(this.options, "paradexAccount");
            if (Helpers.isTrue(!Helpers.isEqual(cachedAccount, null)))
            {
                return cachedAccount;
            }
            this.checkRequiredCredentials();
            Object systemConfig = (this.getSystemConfig()).join();
            Object domain = (this.prepareParadexDomain(true)).join();
            Object messageTypes = new java.util.HashMap<String, Object>() {{
                put( "Constant", new java.util.ArrayList<Object>(java.util.Arrays.asList(new java.util.HashMap<String, Object>() {{
        put( "name", "action" );
        put( "type", "string" );
    }})) );
            }};
            Object message = new java.util.HashMap<String, Object>() {{
                put( "action", "STARK Key" );
            }};
            Object msg = this.ethEncodeStructuredData(domain, messageTypes, message);
            Object signature = this.signMessage(msg, this.privateKey);
            Object account = this.retrieveStarkAccount(signature, Helpers.GetValue(systemConfig, "paraclear_account_hash"), Helpers.GetValue(systemConfig, "paraclear_account_proxy_hash"));
            Helpers.addElementToObject(this.options, "paradexAccount", account);
            return account;
        });

    }

    public java.util.concurrent.CompletableFuture<Object> onboarding(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object account = (this.retrieveAccount()).join();
            Object req = new java.util.HashMap<String, Object>() {{
                put( "action", "Onboarding" );
            }};
            Object domain = (this.prepareParadexDomain()).join();
            Object messageTypes = new java.util.HashMap<String, Object>() {{
                put( "Constant", new java.util.ArrayList<Object>(java.util.Arrays.asList(new java.util.HashMap<String, Object>() {{
        put( "name", "action" );
        put( "type", "felt" );
    }})) );
            }};
            Object msg = this.starknetEncodeStructuredData(domain, messageTypes, req, Helpers.GetValue(account, "address"));
            Object signature = this.starknetSign(msg, Helpers.GetValue(account, "privateKey"));
            Helpers.addElementToObject(parameters, "signature", signature);
            Helpers.addElementToObject(parameters, "account", Helpers.GetValue(account, "address"));
            Helpers.addElementToObject(parameters, "public_key", Helpers.GetValue(account, "publicKey"));
            Object response = (this.privatePostOnboarding(parameters)).join();
            return response;
        });

    }

    public java.util.concurrent.CompletableFuture<Object> authenticateRest(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object cachedToken = this.safeString(this.options, "authToken");
            Object now = this.nonce();
            if (Helpers.isTrue(!Helpers.isEqual(cachedToken, null)))
            {
                Object cachedExpires = this.safeInteger(this.options, "expires");
                if (Helpers.isTrue(Helpers.isLessThan(now, cachedExpires)))
                {
                    return cachedToken;
                }
            }
            Object account = (this.retrieveAccount()).join();
            // https://docs.paradex.trade/api-reference/general-information/authentication
            Object expires = Helpers.add(now, 180);
            final Object finalNow = now;
            Object req = new java.util.HashMap<String, Object>() {{
                put( "method", "POST" );
                put( "path", "/v1/auth" );
                put( "body", "" );
                put( "timestamp", finalNow );
                put( "expiration", expires );
            }};
            Object domain = (this.prepareParadexDomain()).join();
            Object messageTypes = new java.util.HashMap<String, Object>() {{
                put( "Request", new java.util.ArrayList<Object>(java.util.Arrays.asList(new java.util.HashMap<String, Object>() {{
        put( "name", "method" );
        put( "type", "felt" );
    }}, new java.util.HashMap<String, Object>() {{
        put( "name", "path" );
        put( "type", "felt" );
    }}, new java.util.HashMap<String, Object>() {{
        put( "name", "body" );
        put( "type", "felt" );
    }}, new java.util.HashMap<String, Object>() {{
        put( "name", "timestamp" );
        put( "type", "felt" );
    }}, new java.util.HashMap<String, Object>() {{
        put( "name", "expiration" );
        put( "type", "felt" );
    }})) );
            }};
            Object msg = this.starknetEncodeStructuredData(domain, messageTypes, req, Helpers.GetValue(account, "address"));
            Object signature = this.starknetSign(msg, Helpers.GetValue(account, "privateKey"));
            Helpers.addElementToObject(parameters, "signature", signature);
            Helpers.addElementToObject(parameters, "account", Helpers.GetValue(account, "address"));
            Helpers.addElementToObject(parameters, "timestamp", Helpers.GetValue(req, "timestamp"));
            Helpers.addElementToObject(parameters, "expiration", Helpers.GetValue(req, "expiration"));
            Object response = (this.privatePostAuth(parameters)).join();
            //
            // {
            //     jwt_token: "ooooccxtooootoooootheoooomoonooooo"
            // }
            //
            Object token = this.safeString(response, "jwt_token");
            Helpers.addElementToObject(this.options, "authToken", token);
            Helpers.addElementToObject(this.options, "expires", expires);
            return token;
        });

    }

    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        // {
        //     "account": "0x4638e3041366aa71720be63e32e53e1223316c7f0d56f7aa617542ed1e7512x",
        //     "avg_fill_price": "26000",
        //     "client_id": "x1234",
        //     "cancel_reason": "NOT_ENOUGH_MARGIN",
        //     "created_at": 1681493746016,
        //     "flags": [
        //         "REDUCE_ONLY"
        //     ],
        //     "id": "123456",
        //     "instruction": "GTC",
        //     "last_updated_at": 1681493746016,
        //     "market": "BTC-USD-PERP",
        //     "price": "26000",
        //     "published_at": 1681493746016,
        //     "received_at": 1681493746016,
        //     "remaining_size": "0",
        //     "seq_no": 1681471234972000000,
        //     "side": "BUY",
        //     "size": "0.05",
        //     "status": "NEW",
        //     "stp": "EXPIRE_MAKER",
        //     "timestamp": 1681493746016,
        //     "trigger_price": "26000",
        //     "type": "MARKET"
        // }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(order, "created_at");
        Object orderId = this.safeString(order, "id");
        Object clientOrderId = this.omitZero(((String)this.safeString(order, "client_id")));
        Object marketId = this.safeString(order, "market");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object price = this.safeString(order, "price");
        Object amount = this.safeString(order, "size");
        Object orderType = this.safeString(order, "type");
        Object cancelReason = this.safeString(order, "cancel_reason");
        Object status = this.safeString(order, "status");
        if (Helpers.isTrue(!Helpers.isEqual(cancelReason, null)))
        {
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(cancelReason, "NOT_ENOUGH_MARGIN")) || Helpers.isTrue(Helpers.isEqual(cancelReason, "ORDER_EXCEEDS_POSITION_LIMIT"))))
            {
                status = "rejected";
            } else
            {
                status = "canceled";
            }
        }
        Object side = this.safeStringLower(order, "side");
        Object average = this.omitZero(((String)this.safeString(order, "avg_fill_price")));
        Object remaining = this.omitZero(((String)this.safeString(order, "remaining_size")));
        Object lastUpdateTimestamp = this.safeInteger(order, "last_updated_at");
        Object flags = this.safeList(order, "flags", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object reduceOnly = null;
        if (Helpers.isTrue(Helpers.inOp(flags, "REDUCE_ONLY")))
        {
            reduceOnly = true;
        }
        final Object finalStatus = status;
        final Object finalReduceOnly = reduceOnly;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", orderId );
            put( "clientOrderId", clientOrderId );
            put( "timestamp", timestamp );
            put( "datetime", ParadexCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "lastUpdateTimestamp", lastUpdateTimestamp );
            put( "status", ParadexCore.this.parseOrderStatus(finalStatus) );
            put( "symbol", symbol );
            put( "type", ParadexCore.this.parseOrderType(orderType) );
            put( "timeInForce", ParadexCore.this.parseTimeInForce(ParadexCore.this.safeString(order, "instruction")) );
            put( "postOnly", null );
            put( "reduceOnly", finalReduceOnly );
            put( "side", side );
            put( "price", price );
            put( "triggerPrice", ParadexCore.this.safeString(order, "trigger_price") );
            put( "takeProfitPrice", null );
            put( "stopLossPrice", null );
            put( "average", average );
            put( "amount", amount );
            put( "filled", null );
            put( "remaining", remaining );
            put( "cost", null );
            put( "trades", null );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "cost", null );
                put( "currency", null );
            }} );
            put( "info", order );
        }}, market);
    }

