    public Object parseTransfer(Object transfer, Object... optionalArgs)
    {
        //
        //     {
        //         "id": "1718940471200201703989430000",
        //         "account": "0x49ddd7a564c978f6e4089ff8355b56a42b7e2d48ba282cb5aad60f04bea0ec3",
        //         "kind": "DEPOSIT",
        //         "status": "COMPLETED",
        //         "amount": "100000",
        //         "token": "USDC",
        //         "created_at": 1718940471208,
        //         "last_updated_at": 1718941455546,
        //         "txn_hash": "0x73a415ca558a97bbdcd1c43e52b45f1e0486a0a84b3bb4958035ad6c59cb866",
        //         "external_txn_hash": "",
        //         "socialized_loss_factor": ""
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object currencyId = this.safeString(transfer, "token");
        Object code = this.safeCurrencyCode(currencyId, currency);
        Object timestamp = this.safeInteger(transfer, "created_at");
        Object kind = this.safeString(transfer, "kind");
        Object fromAccount = null;
        Object toAccount = null;
        if (Helpers.isTrue(Helpers.isEqual(kind, "DEPOSIT")))
        {
            fromAccount = "external";
            toAccount = "account";
        } else if (Helpers.isTrue(Helpers.isEqual(kind, "WITHDRAWAL")))
        {
            fromAccount = "account";
            toAccount = "external";
        }
        final Object finalFromAccount = fromAccount;
        final Object finalToAccount = toAccount;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transfer );
            put( "id", ParadexCore.this.safeString(transfer, "id") );
            put( "timestamp", timestamp );
            put( "datetime", ParadexCore.this.iso8601(timestamp) );
            put( "currency", code );
            put( "amount", ParadexCore.this.safeNumber(transfer, "amount") );
            put( "fromAccount", finalFromAccount );
            put( "toAccount", finalToAccount );
            put( "status", ParadexCore.this.parseTransactionStatus(ParadexCore.this.safeString(transfer, "status")) );
        }};
    }

    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // fetchDeposits & fetchWithdrawals
        //
        //     {
        //         "id": "1718940471200201703989430000",
        //         "account": "0x49ddd7a564c978f6e4089ff8355b56a42b7e2d48ba282cb5aad60f04bea0ec3",
        //         "kind": "DEPOSIT",
        //         "status": "COMPLETED",
        //         "amount": "100000",
        //         "token": "USDC",
        //         "created_at": 1718940471208,
        //         "last_updated_at": 1718941455546,
        //         "txn_hash": "0x73a415ca558a97bbdcd1c43e52b45f1e0486a0a84b3bb4958035ad6c59cb866",
        //         "external_txn_hash": "",
        //         "socialized_loss_factor": ""
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(transaction, "id");
        Object address = this.safeString(transaction, "account");
        Object txid = this.safeString(transaction, "txn_hash");
        Object currencyId = this.safeString(transaction, "token");
        Object code = this.safeCurrencyCode(currencyId, currency);
        Object timestamp = this.safeInteger(transaction, "created_at");
        Object updated = this.safeInteger(transaction, "last_updated_at");
        Object type = this.safeString(transaction, "kind");
        type = ((Helpers.isTrue((Helpers.isEqual(type, "DEPOSIT"))))) ? "deposit" : "withdrawal";
        Object status = this.parseTransactionStatus(this.safeString(transaction, "status"));
        Object amount = this.safeNumber(transaction, "amount");
        final Object finalType = type;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", id );
            put( "txid", txid );
            put( "timestamp", timestamp );
            put( "datetime", ParadexCore.this.iso8601(timestamp) );
            put( "network", null );
            put( "address", address );
            put( "addressTo", address );
            put( "addressFrom", null );
            put( "tag", null );
            put( "tagTo", null );
            put( "tagFrom", null );
            put( "type", finalType );
            put( "amount", amount );
            put( "currency", code );
            put( "status", status );
            put( "updated", updated );
            put( "internal", null );
            put( "comment", null );
            put( "fee", null );
        }};
    }

    public Object parseTransactionStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "PENDING", "pending" );
            put( "AVAILABLE", "pending" );
            put( "COMPLETED", "ok" );
            put( "FAILED", "failed" );
        }};
        return this.safeString(statuses, ((String)status), status);
    }

